def adjList(n, edges):
    adj = [[] for _ in range(n)]
    for u, v in edges:
        if v not in adj[u]:
            adj[u].append(v)
        if u not in adj[v]:
            adj[v].append(u)
    return [sorted(neighbors) for neighbors in adj]

def adjList(n, edges):
    adj = [[] for _ in range(n)]
    for u, v in edges:
        if u != v and v not in adj[u]:
            adj[u].append(v)
        if u != v and u not in adj[v]:
            adj[v].append(u)
    for i in range(n):
        adj[i].sort()
    return adj

def isValid(s: str) -> bool:
    stack = []
    mapping = {")": "(", "}": "{", "]": "["}
    for char in s:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping:
            if not stack or mapping[char] != stack.pop():
                return False
        else:
            return False
    return not stack

